 42	/* Extended Euclidean Algorithm to compute modulo inverse */
 43	static int modulo_multiplicative_inverse(const int a, const int m)
 44	{
 45	  DevAssert(a < m);
 46	  int t = 0;
 47	  int newt = 1;
 48	  int r = m;
 49	  int newr = a;
 50	
 51	  while (newr != 0) {
 52	    const int q = r / newr;
 53	    int tmp = t;
 54	    t = newt;
 55	    newt = tmp - q * newt;
 56	    tmp = r;
 57	    r = newr;
 58	    newr = tmp - q * newr;
 59	  }
 60	
 61	  AssertFatal(r <= 1, "Modulo inverse doesn't exist for a %d, m %d\n", a, m);
 62	  t = (t < 0) ? t + m : t;
 63	  LOG_D(PHY, "Modulo %d inverse of %d is %d\n", m, a, t);
 64	  return t;
 65	}
